import { useState,useEffect } from "react";
import { socket } from "../socket";
import Message from "./Message";
import EmojiPicker from "emoji-picker-react";

function Chat({ user }) {
  const [room,setRoom]=useState("global");
  const [text,setText]=useState("");
  const [messages,setMessages]=useState([]);
  const [typing,setTyping]=useState("");
  const [showEmoji,setShowEmoji]=useState(false);
  const socket = io("http://localhost:8000/ws");


  useEffect(()=>{
    socket.emit("join_room",{room,user});

    socket.on("receive_message",(msg)=>{
      setMessages(prev=>[...prev,msg]);
    });

    socket.on("typing",(data)=>{
      setTyping(data.user);
      setTimeout(()=>setTyping(""),1500);
    });

  },[room]);

  const send=()=>{
    const msg={
      sender:user,
      room,
      text,
      time:new Date().toLocaleTimeString(),
      seen:false
    };
    socket.emit("send_message",msg);
    setMessages(prev=>[...prev,msg]);
    setText("");
  };

  return (
    <div className="chat-app">
      <header>💬 Chat App</header>

      <div className="chat-box">
        {messages.map((m,i)=><Message key={i} msg={m} user={user}/>)}
      </div>

      {typing && <p>{typing} typing...</p>}

      {showEmoji && <EmojiPicker onEmojiClick={(e)=>setText(text+e.emoji)}/>}

      <input value={text} onChange={e=>setText(e.target.value)} onKeyPress={()=>socket.emit("typing",{user,room})}/>
      <button onClick={()=>setShowEmoji(!showEmoji)}>😀</button>
      <button onClick={send}>Send</button>
    </div>
  );
}

export default Chat;
